// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new tree node
Node* createNode(int value) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->value = value;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}
// Function to add a new level to the tree
void addLevel(Node* root, int level) {
    if (level == 0) return;
    if (root->left == NULL) {
        root->left = createNode(root->value * 2);
        root->right = createNode(root->value * 2 + 1);
    }
    addLevel(root->left, level - 1);
    addLevel(root->right, level - 1);
}
// Function to delete a subtree
void deleteSubtree(Node* root) {
    if (root == NULL) return;
    deleteSubtree(root->left);
    deleteSubtree(root->right);
    free(root);
}
// Function to count the number of nodes in the tree
int countNodes(Node* root) {
    if (root == NULL) return 0;
    return 1 + countNodes(root->left) + countNodes(root->right);
}
int main() {
    int M;
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int Q;
        scanf("%d", &Q);
        Node* root = createNode(1);
        for (int j = 0; j < Q; j++) {
            int cmd;
            scanf("%d", &cmd);
            if (cmd == 1) {
                int T;
                scanf("%d", &T);
                addLevel(root, T);
            } else {
                char commands[100000];
                scanf("%s", commands);
                Node* current = root;
                for (int k = 0; k < strlen(commands); k++) {
                    if (commands[k] == 'L') {
                        current = current->left;
                    } else {
                        current = current->right;
                    }
                }
                deleteSubtree(current);
            }
            printf("%d\n", countNodes(root) % MOD);
        }
    }
    return 0;
}

