    // Define the structure for a tree node
    static class Node {
        int value;
        Node left;
        Node right;
        Node(int value) {
            this.value = value;
            this.left = null;
            this.right = null;
        }
    }
    // Function to create a new tree node
    static Node createNode(int value) {
        return new Node(value);
    }
    // Function to add a new level to the tree
    static void addLevel(Node root, int level) {
        if (level == 0) return;
        if (root.left == null) {
            root.left = createNode(root.value * 2);
            root.right = createNode(root.value * 2 + 1);
        }
        addLevel(root.left, level - 1);
        addLevel(root.right, level - 1);
    }
    // Function to delete a subtree
    static void deleteSubtree(Node root) {
        if (root == null) return;
        deleteSubtree(root.left);
        deleteSubtree(root.right);
    }
    // Function to count the number of nodes in the tree
    static int countNodes(Node root) {
        if (root == null) return 0;
        return 1 + countNodes(root.left) + countNodes(root.right);
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int M = scanner.nextInt();
        for (int i = 0; i < M; i++) {
            int Q = scanner.nextInt();
            Node root = createNode(1);
            for (int j = 0; j < Q; j++) {
                int cmd = scanner.nextInt();
                if (cmd == 1) {
                    int T = scanner.nextInt();
                    addLevel(root, T);
                } else {
                    String commands = scanner.next();
                    Node current = root;
                    for (int k = 0; k < commands.length(); k++) {
                        if (commands.charAt(k) == 'L') {
                            current = current.left;
                        } else {
                            current = current.right;
                        }
                    }
                    deleteSubtree(current);
                }
                System.out.println(countNodes(root) % MOD);
            }
        }
    }
}

